        GREETINGS_ADVENTURER_I_M_SO_GLAD_YOU_VE                              = 6683,  -- Greetings adventurer! I'm so glad you've come, kupo! To celebrate the safe recovery of all eleven of King Kupofried's mog tablets, we're offering a limited-time teleportation service for the low, low price of # gil! What do you say?
        TELEPORT_TO_WHERE_COST_GIL_NOWHERE_SAN_D                             = 6684,  -- Teleport to where? (Cost: # gil.) Nowhere. San d'Oria. Bastok. Windurst. Selbina. Mhaura.
        YOUR_WISH_IS_MY_COMMAND_KUPO_FOR_A                                   = 6685,  -- Your wish is my command, kupo! For a small fee of # gil, that is...
