        OUTSIDE_OF_TOWN_YOU_MIGHT_BE_ABLE_TO                                 = 7872,  -- Outside of town, you might be able to get work from one of the people I'm about to list for you.
        YOU_CAN_FIND_THEM_IN                                                 = 7873,  -- You can find them in [Pashhow Marshlands/Carpenter's Landing deep in Northern San d'Oria/Riverne-Site #A01 in Tavnazia/Uleguerand Range/Oldton Movalpolos deep in North Gustaberg/Xarcabard/Boneyard Gully deep in Attohwa Chasm/La Theine Plateau/Monastic Cavern in Davoi/Qulun Dome in Beadeaux/The Altar Room in Castle Oztroja/Past Pashhow Marshlands].
        INQUIRE_ABOUT_WHICH_LOCALE_NONE_TAVNAZIA_INDIVIDUAL_OTHER            = 7874,  -- Inquire about which locale? None. Tavnazia: # individual[/s]. Other: # individual[/s].
        THE_FOLLOWING_PEOPLE_IN_TAVNAZIA_MAY_HAVE_SOME                       = 7875,  -- The following people in Tavnazia may have some tasks for you.
        WHO_WILL_YOU_GO_SEE_IN_MHAURA_NO                                     = 7876,  -- Who will you go see in Mhaura? No one. Fyi Chalmwoh. Rycharde. Rycharde. Lacia. Vera. Orlando. Rycharde. Rycharde. Take. Rycharde. Rycharde. Celestina. Nereus. Ripapa. Keshab-Menjab. Katsunaga.
