        FLANDIACE_RIGHT_IN_FRONT_OF_ME_CAN_PROVIDE                           = 7882,  -- Flandiace right in front of me can provide you with more information.
        IF_YOU_OPEN_THE_MAIN_MENU_AND_PRESS                                  = 7883,  -- If you open the main menu and press the right arrow key, you'll come across an entry called Help Desk.
        SELECTING_THAT_OPTION_AND_THEN_CLICKING_HELP_DESK                    = 7884,  -- Selecting that option and then clicking Help Desk again brings up a small list, of which one entry reads I need help with the game controls.
        THERE_S_A_LOT_OF_SPECIFIC_EXAMPLES_THAT                              = 7885,  -- There's a lot of specific examples that might help you out, so give it a look if you're unclear on something.
        I_LL_MARK_THAT_PERSON_S_LOCATION_ON                                  = 7886,  -- I'll mark that person's location on your map to make finding them easier. Never forget how useful your map can be!
        SOMEPLACE_SPECIAL_HMM_WELL_IT_WOULDN_T_DO                            = 7887,  -- Someplace special, hmm? Well, it wouldn't do for you to get lost along the way, so let me mark that spot on your map.
        BE_SURE_TO_TAKE_A_GOOD_LOOK                                          = 7888,  -- Be sure to take a good look!
        FINALLY_SOME_INFORMATION_TO_HELP_YOU_IN_YOUR                         = 7889,  -- FiNAllY, sOmE InFOrmAtiOn tO hELp yOu In yoUr TrAVelS.
        ONE_MORE_THING                                                       = 7890,  -- One more thing.
        I_HAVE_SAVED_A_RATHER_PARAMOUNT_DETAIL_FOR                           = 7891,  -- I have saved a rather paramount detail for last. Allow me to explain.
        THERE_S_STILL_ONE_OTHER_THING_REMAINING_TO                           = 7892,  -- There's still one other thing remaining to share with you.
        YOU_CAN_WARP_BETWEEN_PLACES_KNOWN_AS_HOME                            = 7893,  -- YoU CAn wArP BetWEen PlACes KnOwn aS HoME pOinTs. TheY ARe moST CoNveNieNT, sO maKe SuRE to ReGIsTer ThEM bY TouCHing ThE SurFaCE.
        HOME_POINTS_WILL_PROBABLY_TURN_OUT_TO_BE                             = 7894,  -- Home points will probably turn out to be among your best companions. Make sure to examine one if you find it, so you can warp between them and cover large distances fast.
        YOU_MAY_TELEPORT_BETWEEN_THESE_CRYSTALLINE_NODES_CALLED              = 7895,  -- You may teleport between these crystalline nodes called home points for efficient travel. Be sure to examine any you stumble upon.
        THERE_S_SOME_SPECIAL_CRYSTAL_NODES_KNOWN_AS                          = 7896,  -- There's some special crystal nodes known as home points that'll undoubtedly serve you well. Don't forget to interact with all that you find, as they can help you get to far away places.
        IF_YOU_FIND_YOURSELF_IN_A_FARAWAY_PLACE                              = 7897,  -- If yOU fINd yOurSeLF iN A fARaWay pLaCe, maKe sURe tO FinD a StoRE to BuY a Map fROm! wIth a MaP, yoU CaN ChEck WheRe yOu ArE!
        SHOULD_YOU_FIND_YOURSELF_LOST_IN_THE_MIDDLE                          = 7898,  -- Should you find yourself lost in the middle of nowhere, try to make it back to town to buy a map. That way, you can get your bearings.
        REMEMBER_TO_PURCHASE_A_MAP_FROM_THE_APPROPRIATE                      = 7899,  -- Remember to purchase a map from the appropriate vendor before going to a faraway land. If you do, you can check your location within that place.
        DID_YOU_KNOW_THAT_SOME_VENDORS_WILL_SELL                             = 7900,  -- Did you know that some vendors will sell you maps of specific areas? It sure beats stumbling around like a dullard!
        DON_T_WASTE_PRECIOUS_ITEMS_BY_SELLING_THEM                           = 7901,  -- DoN'T WaSTe pRecIOus iTemS By sEllINg tHeM tO a StoRe. MaKE eVen MoRe MonEy By PuTTing tHeM uP At tHe AucTIon HouSe!
        I_HATE_TO_SAY_IT_BUT_THE_MERCHANTS                                   = 7902,  -- I hate to say it, but the merchants around here are pretty stingy. You'd have more luck listing any unwanted goods at the auction house.
        I_ADVISE_YOU_TO_PUT_ANY_UNWANTED_GOODS                               = 7903,  -- I advise you to put any unwanted goods up for sale at the auction house rather than be taken advantage of by the vendors here.
        IF_THERE_S_SOMETHING_YOU_VE_GOT_THAT                                 = 7904,  -- If there's something you've got that you don't need, try putting it up at the auction house rather than selling it to some unscrupulous vendor.
        MANY_UNDEAD_MONSTERS_CAN_SENSE_WHEN_YOU_ARE                          = 7905,  -- MaNY uNdEaD MOnsTeRS cAn SenSe WhEn yOU Are LoW oN HP, aNd wIll TAke tHaT opPOrtUnItY tO ComE AfTEr yOu!
        UNDEAD_ENEMIES_TEND_TO_COME_OUT_OF_THE                               = 7906,  -- Undead enemies tend to come out of the woodwork when your HP is low. Be careful.
        THE_UNDEAD_OFTEN_ASSAULT_ADVENTURERS_WITH_LOW_HP                     = 7907,  -- The undead often assault adventurers with low HP, which is all the more reason to never let your guard down in the wilderness.
        UNDEAD_ARE_ALWAYS_OUT_FOR_BLOOD_AND_BRAINS                           = 7908,  -- Undead are always out for blood and brains, so watch out if you're low on health! They'll make a beeline right for you.
        LET_S_TALK_ABOUT_ATTRIBUTES_INCREASING_YOUR_STRENGTH                 = 7909,  -- LeT'S tALk aBouT AttRIButeS. InCReaSing yoUr StrenGTh (STR) wiLL iNcrEase YouR pHYsiCal, bUt NOt MaGiCal, AttACk.
        INCREASING_YOUR_STRENGTH_STR_RAISES_YOUR_ATTACK_POWER                = 7910,  -- Increasing your strength (STR) raises your attack power, but--sadly--not your magic attack.
        INCREASING_YOUR_STRENGTH_STR_ENHANCES_YOUR_ATTACK_POWER              = 7911,  -- Increasing your strength (STR) enhances your attack power, but--regrettably--does nothing for your magic attack.
        INCREASING_YOUR_STRENGTH_STR_ENHANCES_YOUR_ATTACK_POWER_2            = 7912,  -- Increasing your strength (STR) enhances your attack power, but unfortunately does nothing for the efficacy of your magic.
        LET_S_TALK_ABOUT_ATTRIBUTES_INCREASING_YOUR_DEXTERITY                = 7913,  -- LeT'S tALk aBouT AttRIButeS. InCReaSinG yoUr DeXteRIty (DEX) wiLl IncReaSe yOuR AccURacY aNd cRiTIcaL HIt rAtE.
